export const UsageMetadataSchema = {
  type: 'object',
  description: "Metadata on the generation request's token usage.",
  properties: {
    promptTokenCount: {
      type: 'integer',
      format: 'int32',
      description:
        'Number of tokens in the prompt. When `cached_content` is set, this is still the total effective prompt size meaning this includes the number of tokens in the cached content.',
    },
    cachedContentTokenCount: {
      type: 'integer',
      format: 'int32',
      description:
        'Number of tokens in the cached part of the prompt (the cached content)',
    },
    candidatesTokenCount: {
      type: 'integer',
      format: 'int32',
      description:
        'Total number of tokens across all the generated response candidates.',
    },
    toolUsePromptTokenCount: {
      type: 'integer',
      format: 'int32',
      description:
        'Output only. Number of tokens present in tool-use prompt(s).',
    },
    thoughtsTokenCount: {
      type: 'integer',
      format: 'int32',
      description:
        'Output only. Number of tokens of thoughts for thinking models.',
    },
    totalTokenCount: {
      type: 'integer',
      format: 'int32',
      description:
        'Total token count for the generation request (prompt + thoughts + response candidates).',
    },
    promptTokensDetails: {
      type: 'array',
      description:
        'Output only. List of modalities that were processed in the request input.',
      items: { $ref: '#/$defs/ModalityTokenCount' },
    },
    cacheTokensDetails: {
      type: 'array',
      description:
        'Output only. List of modalities of the cached content in the request input.',
      items: { $ref: '#/$defs/ModalityTokenCount' },
    },
    candidatesTokensDetails: {
      type: 'array',
      description:
        'Output only. List of modalities that were returned in the response.',
      items: { $ref: '#/$defs/ModalityTokenCount' },
    },
    toolUsePromptTokensDetails: {
      type: 'array',
      description:
        'Output only. List of modalities that were processed for tool-use request inputs.',
      items: { $ref: '#/$defs/ModalityTokenCount' },
    },
    serviceTier: {
      type: 'string',
      description: 'Output only. Service tier of the request.',
      enum: ['unspecified', 'standard', 'flex', 'priority'],
    },
  },
  $defs: {
    ModalityTokenCount: {
      type: 'object',
      description: 'Represents token counting info for a single modality.',
      properties: {
        modality: {
          type: 'string',
          description: 'The modality associated with this token count.',
          enum: [
            'MODALITY_UNSPECIFIED',
            'TEXT',
            'IMAGE',
            'VIDEO',
            'AUDIO',
            'DOCUMENT',
          ],
        },
        tokenCount: {
          type: 'integer',
          format: 'int32',
          description: 'Number of tokens.',
        },
      },
    },
  },
} as const

